def solve(arg1):
    track_data = arg1[0]
    track = track_data['track']
    gamma_intensity = track_data['gamma_intensity']
    theta_intensity = track_data['theta_intensity']

    total_intensity = gamma_intensity + theta_intensity
    inclusion_percentage = (total_intensity / 100) * 100  # Assuming max intensity is 100 for percentage calculation

    if track == 'silent_track':
        inclusion_percentage = 0
        listenability = 'pass'
    elif inclusion_percentage >= 100:
        listenability = 'fail'
    elif inclusion_percentage < 50:
        listenability = 'pass'
    else:
        listenability = 'fail'

    return {
        'inclusion_percentage': inclusion_percentage,
        'listenability': listenability
    }
